// ══════════════════════════════════════════════════════════════
// EVEZ WF9 — 10-Node Free Inference Mesh
// Routes LLM requests across 10 providers based on task type,
// rate limits, and poly_c signal. $0.00/day.
// ══════════════════════════════════════════════════════════════

function H(d){let h=5381,s=typeof d==='string'?d:JSON.stringify(d);for(let i=0;i<s.length;i++){h=((h<<5)+h)+s.charCodeAt(i);h|=0;}return 'sha_'+Math.abs(h).toString(16).padStart(16,'0');}
async function log(t,p){try{await $fetch('https://evezos.app.n8n.cloud/webhook/evez-ledger',{method:'POST',body:{event_type:t,payload:{...p,pid:335,ts:new Date().toISOString()}}});}catch(e){}}

const ts = new Date().toISOString();
const b = $input.first()?.json?.body || $input.first()?.json || {};

// ── INPUT ─────────────────────────────────────────────────────────────────
const task     = b.task || b.task_type || 'default';
const prompt   = b.prompt || b.message || b.query || '';
const system   = b.system || 'You are the EVEZ-OS synthesis engine. Respond concisely in JSON when asked.';
const maxTok   = parseInt(b.max_tokens || '800');
const polyCHint= parseFloat(b.poly_c || '0');

if (!prompt) {
  return [{json:{error:'No prompt provided. POST {task,prompt} to /webhook/evez-mesh'}}];
}

// ── ROUTING TABLE ────────────────────────────────────────────────────────
// Priority order per task type — first available key wins
const ROUTING = {
  reasoning:    ['github', 'sambanova', 'groq', 'gemini', 'cerebras'],
  code:         ['mistral', 'github', 'groq', 'cerebras', 'gemini'],
  fast:         ['groq', 'cerebras', 'gemini', 'mistral', 'openrouter'],
  fire_event:   ['github', 'gemini', 'groq', 'cerebras', 'mistral'],
  arxiv_score:  ['cerebras', 'groq', 'gemini', 'openrouter', 'mistral'],
  long_context: ['gemini', 'mistral', 'github', 'groq'],
  default:      ['groq', 'cerebras', 'gemini', 'mistral', 'openrouter', 'github'],
};

// Auto-upgrade task based on poly_c signal
let effectiveTask = task;
if (polyCHint >= 8.0)  effectiveTask = 'reasoning';    // critical mass → o3/405B
else if (polyCHint >= 5.0) effectiveTask = 'fire_event'; // canonical → GPT-4o/70B
else if (polyCHint >= 0.9) effectiveTask = 'fast';        // standard → Groq

const priority = ROUTING[effectiveTask] || ROUTING['default'];

// ── PROVIDER CALL FUNCTIONS ───────────────────────────────────────────────
async function callGroq(sys, usr, max) {
  const k=$env.GROQ_API_KEY; if(!k) throw new Error('No key');
  const model='llama-3.3-70b-versatile';
  const r=await $fetch('https://api.groq.com/openai/v1/chat/completions',{
    method:'POST',headers:{'Authorization':`Bearer ${k}`,'Content-Type':'application/json'},
    body:JSON.stringify({model,max_tokens:max,messages:[{role:'system',content:sys},{role:'user',content:usr}]})
  });
  return {content:r.choices[0].message.content, model, tokens:r.usage?.total_tokens||0};
}

async function callGemini(sys, usr, max) {
  const k=$env.GEMINI_API_KEY; if(!k) throw new Error('No key');
  const model='gemini-2.0-flash';
  const r=await $fetch(`https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${k}`,{
    method:'POST',headers:{'Content-Type':'application/json'},
    body:JSON.stringify({systemInstruction:{parts:[{text:sys}]},contents:[{role:'user',parts:[{text:usr}]}],generationConfig:{maxOutputTokens:max}})
  });
  return {content:r.candidates[0].content.parts[0].text, model, tokens:r.usageMetadata?.totalTokenCount||0};
}

async function callOpenRouter(sys, usr, max) {
  const k=$env.OPENROUTER_API_KEY; if(!k) throw new Error('No key');
  const model='meta-llama/llama-4-scout:free';
  const r=await $fetch('https://openrouter.ai/api/v1/chat/completions',{
    method:'POST',headers:{'Authorization':`Bearer ${k}`,'Content-Type':'application/json','HTTP-Referer':'https://evez-os.autonomous'},
    body:JSON.stringify({model,max_tokens:max,messages:[{role:'system',content:sys},{role:'user',content:usr}]})
  });
  return {content:r.choices[0].message.content, model, tokens:r.usage?.total_tokens||0};
}

async function callCerebras(sys, usr, max) {
  const k=$env.CEREBRAS_API_KEY; if(!k) throw new Error('No key');
  const model='llama-3.3-70b';
  const r=await $fetch('https://api.cerebras.ai/v1/chat/completions',{
    method:'POST',headers:{'Authorization':`Bearer ${k}`,'Content-Type':'application/json'},
    body:JSON.stringify({model,max_tokens:max,messages:[{role:'system',content:sys},{role:'user',content:usr}]})
  });
  return {content:r.choices[0].message.content, model, tokens:r.usage?.total_tokens||0};
}

async function callMistral(sys, usr, max) {
  const k=$env.MISTRAL_API_KEY; if(!k) throw new Error('No key');
  const model='mistral-small-latest';
  const r=await $fetch('https://api.mistral.ai/v1/chat/completions',{
    method:'POST',headers:{'Authorization':`Bearer ${k}`,'Content-Type':'application/json'},
    body:JSON.stringify({model,max_tokens:max,messages:[{role:'system',content:sys},{role:'user',content:usr}]})
  });
  return {content:r.choices[0].message.content, model, tokens:r.usage?.total_tokens||0};
}

async function callGitHub(sys, usr, max) {
  const k=$env.GITHUB_ACCESS_TOKEN; if(!k) throw new Error('No key');
  // GitHub Models: gpt-4o is free with GitHub account
  const model='gpt-4o';
  const r=await $fetch('https://models.inference.ai.azure.com/chat/completions',{
    method:'POST',headers:{'Authorization':`Bearer ${k}`,'Content-Type':'application/json'},
    body:JSON.stringify({model,max_tokens:max,messages:[{role:'system',content:sys},{role:'user',content:usr}]})
  });
  return {content:r.choices[0].message.content, model:'github/gpt-4o', tokens:r.usage?.total_tokens||0};
}

async function callCohere(sys, usr, max) {
  const k=$env.COHERE_API_KEY; if(!k) throw new Error('No key');
  const r=await $fetch('https://api.cohere.ai/v2/chat',{
    method:'POST',headers:{'Authorization':`Bearer ${k}`,'Content-Type':'application/json'},
    body:JSON.stringify({model:'command-r-plus',max_tokens:max,system_prompt:sys,messages:[{role:'user',content:usr}]})
  });
  return {content:r.message.content[0].text, model:'cohere/command-r-plus', tokens:r.usage?.tokens?.output_tokens||0};
}

async function callHuggingFace(sys, usr, max) {
  const k=$env.HF_TOKEN; if(!k) throw new Error('No key');
  const r=await $fetch('https://api-inference.huggingface.co/models/meta-llama/Llama-3.2-11B-Vision-Instruct/v1/chat/completions',{
    method:'POST',headers:{'Authorization':`Bearer ${k}`,'Content-Type':'application/json'},
    body:JSON.stringify({model:'meta-llama/Llama-3.2-11B-Vision-Instruct',max_tokens:max,messages:[{role:'system',content:sys},{role:'user',content:ur}]})
  });
  return {content:r.choices[0].message.content, model:'hf/llama-3.2-11b', tokens:r.usage?.total_tokens||0};
}

async function callSambanova(sys, usr, max) {
  const k=$env.SAMBANOVA_API_KEY; if(!k) throw new Error('No key');
  const model='Meta-Llama-3.1-405B-Instruct';
  const r=await $fetch('https://api.sambanova.ai/v1/chat/completions',{
    method:'POST',headers:{'Authorization':`Bearer ${k}`,'Content-Type':'application/json'},
    body:JSON.stringify({model,max_tokens:max,messages:[{role:'system',content:sys},{role:'user',content:usr}]})
  });
  return {content:r.choices[0].message.content, model:'sambanova/llama-405b', tokens:r.usage?.total_tokens||0};
}

const CALLERS = {
  groq: callGroq, gemini: callGemini, openrouter: callOpenRouter,
  cerebras: callCerebras, mistral: callMistral, github: callGitHub,
  cohere: callCohere, huggingface: callHuggingFace, sambanova: callSambanova,
};

// ── ROUTE THROUGH MESH ────────────────────────────────────────────────────
const tried = [];
let result = null;
let t0 = Date.now();

for (const provider of priority) {
  const caller = CALLERS[provider];
  if (!caller) continue;
  try {
    result = await caller(system, prompt, maxTok);
    result.provider = provider;
    result.latency_ms = Date.now() - t0;
    break;
  } catch(e) {
    tried.push({provider, error: e.message?.slice(0,60)});
  }
}

if (!result) {
  await log('MESH_EXHAUSTED', {task: effectiveTask, tried, ts});
  return [{json:{error:'All nodes exhausted', tried, task: effectiveTask}}];
}

// ── LOG + RETURN ─────────────────────────────────────────────────────────
const out = {
  content:     result.content,
  provider:    result.provider,
  model:       result.model,
  tokens:      result.tokens,
  latency_ms:  result.latency_ms,
  task_type:   effectiveTask,
  poly_c_hint: polyCHint,
  tried_first: tried,
  ts, pid: 335,
  entry_hash:  H({prompt, provider: result.provider, ts}),
};

await log('MESH_CALL', {provider: result.provider, model: result.model, task: effectiveTask, tokens: result.tokens, latency_ms: result.latency_ms});
return [{json: out}];

const envKeys = {groq:'GROQ_API_KEY',gemini:'GEMINI_API_KEY',openrouter:'OPENROUTER_API_KEY',cerebras:'CEREBRAS_API_KEY',mistral:'MISTRAL_API_KEY',github:'GITHUB_ACCESS_TOKEN',cohere:'COHERE_API_KEY',huggingface:'HF_TOKEN',sambanova:'SAMBANOVA_API_KEY'};
const status = {};
for(const [p,k] of Object.entries(envKeys)){
  status[p] = {configured: !!$env[k], key_var: k};
}
const configured = Object.values(status).filter(v=>v.configured).length;
return [{json:{
  version:'WF9 10-Node Inference Mesh',
  pid:335, ts:new Date().toISOString(),
  nodes_configured: configured,
  nodes_total: Object.keys(envKeys).length,
  nodes: status,
  daily_capacity: {
    groq:   '14.4K req (8B) / 1K req (70B)',
    gemini: '1.5K req/day',
    openrouter: '50 req/day (free)',
    cerebras: '1M tokens/day',
    mistral: '1B tokens/month',
    github: '50-150 req/day (GPT-4o/o3)',
    cohere: '1K req/month',
    huggingface: '300 req/hr',
    sambanova: '$5 credit (~30M tokens)',
    cloudflare: '10K neurons/day (in CF Worker)',
  },
  routing: {
    reasoning:   'github → sambanova → groq → gemini → cerebras',
    code:        'mistral → github → groq → cerebras → gemini',
    fast:        'groq → cerebras → gemini → mistral → openrouter',
    fire_event:  'github → gemini → groq → cerebras → mistral',
    arxiv_score: 'cerebras → groq → gemini → openrouter → mistral',
    long_context:'gemini → mistral → github → groq',
    default:     'groq → cerebras → gemini → mistral → openrouter → github',
  },
  poly_c_routing: {
    '>=8.0': 'reasoning (o3/405B)',
    '>=5.0': 'fire_event (GPT-4o/70B)',
    '>=0.9': 'fast (Groq/Cerebras)',
    '<0.9':  'arxiv_score (lightweight)',
  },
  webhook: 'POST /webhook/evez-mesh + {task,prompt,system?,max_tokens?,poly_c?}',
}}];
